queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?fieldname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:fieldId ?cg . ?child a :Fields ; p:id ?cg . ?l p:physicistId ?pg . ?parent a :Physicists ; p:id ?pg . } GROUP BY ?child }
  ?child p:fieldName ?fieldname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Physicists } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?fieldname WHERE {
  ?physicist_fields a :Physicist_Fields .
  ?fields a :Fields .
  ?physicist_fields p:hasFields ?fields .
  ?physicists a :Physicists .
  ?physicist_fields p:hasPhysicists ?physicists .
  ?physicists p:name ?name .
  ?fields p:fieldName ?fieldname .
} }
  collective: { SELECT ?fieldname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:fieldId ?cg . ?child a :Fields ; p:id ?cg . ?l p:physicistId ?pg . ?parent a :Physicists ; p:id ?pg . } GROUP BY ?child }
  ?child p:fieldName ?fieldname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Physicists } }
  FILTER(?nf = ?total)
} }
}
